# Check temperature calculation edge cases
def calc_temp(temperature, attempt):
    if attempt == 0:
        return temperature
    bump = 0.2 * attempt
    return (temperature + bump if temperature + bump <= 1.0
            else max(0.0, temperature - bump))

# Test cases
test_temps = [0.0, 0.5, 1.0]
for temp in test_temps:
    print(f"\nTemperature {temp}:")
    for attempt in range(4):
        new_temp = calc_temp(temp, attempt)
        print(f"  Attempt {attempt}: {new_temp:.2f}")
EOF

